import{_ as t,m as r,k as n,ah as a}from"./chunks/framework.BgQAHmMj.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"fr/developers/getting-started/introduction.md","filePath":"src/fr/developers/getting-started/introduction.md"}'),o={name:"fr/developers/getting-started/introduction.md"};function s(i,e,l,u,c,d){return n(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="qu-est-ce-que-creopse" tabindex="-1">Qu&#39;est-ce que Creopse ? <a class="header-anchor" href="#qu-est-ce-que-creopse" aria-label="Permalink to &quot;Qu&#39;est-ce que Creopse ?&quot;">​</a></h2><p><strong>Creopse</strong> est un CMS hybride et extensible, conçu autour d&#39;un backend <strong>Laravel</strong> ou <strong>Adonis</strong> couplé à un frontend <strong>Vue.js 3</strong> ou <strong>React</strong> via <strong>Inertia.js</strong>. Il embarque à la fois un front-end intégré pour construire des interfaces rapidement, et une API REST pour diffuser le contenu vers n&#39;importe quel client externe.</p><h3 id="pourquoi-hybride" tabindex="-1">Pourquoi &quot;hybride&quot; ? <a class="header-anchor" href="#pourquoi-hybride" aria-label="Permalink to &quot;Pourquoi &quot;hybride&quot; ?&quot;">​</a></h3><p>Les CMS traditionnels (WordPress, Drupal) couplent étroitement le rendu et la donnée : le frontend et le backend partagent le même processus. Les CMS headless vont à l&#39;opposé : ils suppriment tout front-end et exposent uniquement une API. Creopse prend le meilleur des deux approches :</p><ul><li>Un <strong>front-end intégré</strong> pour déployer un site complet sans infrastructure séparée.</li><li>Une <strong>API REST</strong> pour alimenter des applications mobiles, des intégrations tierces ou tout autre client découplé.</li></ul><h3 id="un-systeme-extensible-par-conception" tabindex="-1">Un système extensible par conception <a class="header-anchor" href="#un-systeme-extensible-par-conception" aria-label="Permalink to &quot;Un système extensible par conception&quot;">​</a></h3><p>Creopse repose sur une architecture de plugins: une nouvelle fonctionnalité peut être encapsulée, distribuée et installée de manière indépendante, sans toucher au cœur du système.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><h3 id="configuration-systeme" tabindex="-1">Configuration système <a class="header-anchor" href="#configuration-systeme" aria-label="Permalink to &quot;Configuration système&quot;">​</a></h3><p><strong>Avec un backend Laravel :</strong></p><ul><li><strong>Laravel</strong> : version 10, 11 ou 12.</li><li><strong>PHP</strong> : <ul><li>Laravel 10 : 8.1 minimum.</li><li>Laravel 11 &amp; 12 : 8.2 minimum.</li></ul></li><li><strong>Composer</strong> : gestion des dépendances PHP.</li><li><strong>pnpm</strong> : compilation et gestion des assets frontend.</li></ul><p><strong>Avec un backend Adonis :</strong> <em>(prochainement)</em></p><h3 id="connaissances-recommandees" tabindex="-1">Connaissances recommandées <a class="header-anchor" href="#connaissances-recommandees" aria-label="Permalink to &quot;Connaissances recommandées&quot;">​</a></h3><p>Creopse s&#39;appuie sur des outils existants — une familiarité avec les concepts suivants accélèrera la prise en main :</p><ul><li><strong>Laravel ou Adonis</strong> : routage, middlewares, migrations, ORM.</li><li><strong>Inertia.js</strong> : pont entre le backend et le framework frontend.</li><li><strong>Vue.js 3 ou React</strong> : rendu côté client et gestion d&#39;état.</li></ul><p>Documentation de référence :</p><ul><li><a href="https://laravel.com/docs" target="_blank" rel="noreferrer">Laravel</a></li><li><a href="https://adonisjs.com" target="_blank" rel="noreferrer">Adonis</a></li><li><a href="https://inertiajs.com" target="_blank" rel="noreferrer">Inertia.js</a></li><li><a href="https://vuejs.org" target="_blank" rel="noreferrer">Vue.js 3</a></li><li><a href="https://react.dev" target="_blank" rel="noreferrer">React</a></li></ul><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><ul><li><a href="./core-concepts.html">Concepts de base</a> : les fondamentaux de l&#39;architecture Creopse.</li><li><a href="./installation.html">Installation</a> : mise en place de l&#39;environnement et premier démarrage.</li></ul>',20)])])}const h=t(o,[["render",s]]);export{m as __pageData,h as default};
